// RSS ve API verilerini parse et
const results = [];

for (const item of $input.all()) {
  try {
    const body = item.json.body || item.json;
    const sourceId = item.json.source_id || 1;
    const sourceName = item.json.source_name || 'Bilinmeyen';
    const category = item.json.category || 'genel';

    // RSS XML parsing (basit regex)
    const titleMatch = body.match(/<title>(.*?)<\/title>/g);
    const linkMatch = body.match(/<link>(.*?)<\/link>/g);
    const descMatch = body.match(/<description>(.*?)<\/description>/g);
    const pubDateMatch = body.match(/<pubDate>(.*?)<\/pubDate>/g) || body.match(/<updated>(.*?)<\/updated>/g);

    if (titleMatch && titleMatch.length > 1) { // İlk title channel başlığı
      for (let i = 1; i < titleMatch.length; i++) {
        const title = titleMatch[i].replace(/<[^>]*>/g, '').trim();
        const link = linkMatch && linkMatch[i] ? linkMatch[i].replace(/<[^>]*>/g, '').trim() : '';
        const desc = descMatch && descMatch[i] ? descMatch[i].replace(/<[^>]*>/g, '').trim() : '';
        const pubDate = pubDateMatch && pubDateMatch[i-1] ? pubDateMatch[i-1].replace(/<[^>]*>/g, '').trim() : new Date().toISOString();

        if (title && link) {
          results.push({
            json: {
              source_id: sourceId,
              source_name: sourceName,
              category: category,
              title: title,
              url: link,
              summary: desc,
              published_at: pubDate,
              raw_data: body.substring(0, 5000) // İlk 5000 karakter
            }
          });
        }
      }
    }
  } catch (e) {
    console.error('Parse hatası:', e.message, 'Kaynak:', item.json.source_name);
  }
}

return results;

// Deduplication - Aynı haberi farklı kaynaklardan gelenleri tekilleştir
const crypto = require('crypto');

const items = $input.all();
const seen = {};
const unique = [];

for (const item of items) {
  const title = item.json.title || '';
  const url = item.json.url || '';

  // Başlık ve URL hash'le
  const titleHash = crypto.createHash('sha256').update(title.toLowerCase()).digest('hex');
  const urlHash = crypto.createHash('sha256').update(url.toLowerCase()).digest('hex');

  // Aynı başlık veya URL'yi daha önce görmedikse ekle
  if (!seen[titleHash] && !seen[urlHash]) {
    seen[titleHash] = true;
    seen[urlHash] = true;
    item.json.title_hash = titleHash;
    item.json.content_hash = urlHash;
    unique.push(item);
  }
}

console.log(`${items.length} haber geldi, ${unique.length} benzersiz haber kaldı`);
return unique;

