=Aşağıdaki haberin kategorisini ve önem skorunu belirle.

Başlık: {{ $json.title }}
Özet: {{ $json.summary }}
Kaynak: {{ $json.source_name }}

Kategoriler: teknoloji, ekonomi, kultur, magazin, bilim
Önem skoru: 1-10 arası (10=en önemli)
Dil: tr/en/de/fr vb.

Sadece JSON çıktısı ver:
{"category": "...", "importance_score": 5, "language": "tr", "is_news_worthy": true}

parameters.jsCode:
// AI çıktısını işle ve kaydet
const results = [];

for (const item of $input.all()) {
  try {
    const aiOutput = item.json.output || item.json;
    let category = aiOutput.category || 'genel';
    let importance = aiOutput.importance_score || 5;
    let language = aiOutput.language || 'tr';
    let isNewsWorthy = aiOutput.is_news_worthy !== false;

    // Kategori doğrulama
    const validCategories = ['teknoloji', 'ekonomi', 'kultur', 'magazin', 'bilim'];
    if (!validCategories.includes(category.toLowerCase())) {
      category = 'genel';
    }

    // Önem skoru sınırlama
    importance = Math.max(1, Math.min(10, importance));

    if (isNewsWorthy) {
      results.push({
        json: {
          ...item.json,
          category: category.toLowerCase(),
          importance_score: importance,
          language: language.toLowerCase(),
          status: 'pending'
        }
      });
    }
  } catch (e) {
    console.error('AI output parse hatası:', e.message);
  }
}

console.log(`${results.length} haber kategorize edildi ve kaydedilmeye hazır`);
return results;
